/** Get base experience for a species, with fallback */
export function getBaseExperience(speciesId: string): number {
  return POKEDEX_DATA[speciesId]?.baseExperience ?? 50
}

/** Get EV yield for a species (in Dex stat keys: hp/atk/def/spa/spd/spe) */
export function getEvYield(speciesId: string): Record<string, number> {
  const data = POKEDEX_DATA[speciesId]
  if (data && Object.keys(data.evs).length > 0) return data.evs
  // Fallback: derive from highest base stat
  const { Dex } = require('@pkmn/sim')
  const species = Dex.species.get(speciesId)
  if (!species?.baseStats) return {}
  const stats = Object.entries(species.baseStats as Record<string, number>)
  if (stats.length === 0) return {}
  stats.sort((a, b) => b[1] - a[1])
  const result: Record<string, number> = {}
  if (stats[0]) result[stats[0][0]] = 2
  if (stats[1]) result[stats[1][0]] = 1
  return result
}

/** Get growth rate for a species */
export function getGrowthRate(speciesId: string): string {
  return POKEDEX_DATA[speciesId]?.growthRate ?? 'medium-slow'
}

/** Get capture rate for a species */
export function getCaptureRate(speciesId: string): number {
  return POKEDEX_DATA[speciesId]?.captureRate ?? 45
}

/** Get base happiness for a species */
export function getBaseHappiness(speciesId: string): number {
  return POKEDEX_DATA[speciesId]?.baseHappiness ?? 70
}

/** Get hatch counter (egg cycles). Steps to hatch = hatchCounter * 257. */
export function getHatchCounter(speciesId: string): number {
  if (POKEDEX_DATA[speciesId]?.hatchCounter) return POKEDEX_DATA[speciesId]!.hatchCounter!
  // Fallback: baby/no-evolution Pokémon tend to have ~10-15 cycles,
  // mid-stage ~20, fully evolved ~20-40, legendaries ~80
  const { Dex } = require('@pkmn/sim') as typeof import('@pkmn/sim')
  const species = Dex.species.get(speciesId)
  if (!species?.exists) return 20
  // Legendary/mythical
  if (species.tags?.some((t: string) => t === 'Legendary' || t === 'Mythical' || t === 'Ultra Beast' || t === 'Paradox')) return 80
  // Baby Pokémon (has prevo but no evos)
  if (species.prevo && (!species.evos || species.evos.length === 0)) return 10
  // Base stage (has evos)
  if (species.evos?.length > 0 && !species.prevo) return 20
  // Fully evolved
  if (!species.evos || species.evos.length === 0) return 25
  return 20
}
